A developer deployed a trigger to update the Status__c of Assets related to an Account when the Account's status changes, and a nightly integration that updates Accounts in bulk has started to fail with limit failures.

trigger AccountTrigger on Account (after update) {
    List<Asset> assetsToUpdate = new List<Asset>();
    for (Account newA : Trigger.new) {
        Account oldA = Trigger.oldMap.get(newA.Id);
        if (oldA.Status__c != newA.Status__c) {
            assetsToUpdate.addAll( AccountHelper.getAssetsToUpdate(newA) );
        }
    }
    update assetsToUpdate;
}

public class AccountHelper {
    public static List<Asset> getAssetsToUpdate(Account acct) {
        List<Asset> assetsToUpdate = new List<Asset>();
        for (Asset asst : [SELECT Id, Status__c FROM Asset WHERE AccountId = :acct.Id]) {
            if (asst.Status__c != acct.Status__c) {
                asst.Status__c = acct.Status__c;
                assetsToUpdate.add(asst);
            }
        }
        return assetsToUpdate;
    }
}

